import React from 'react';

export default function Hero() {
  return (
    <section style={{
      position: 'relative', height: '100vh',
      display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center',
      overflow: 'hidden',
      backgroundImage: 'url(https://images.unsplash.com/photo-1529156069898-49953e39b3ac?w=1400)',
      backgroundSize: 'cover', backgroundPosition: 'center',
    }}>

      {/* Gradient overlay */}
      <div style={{
        position: 'absolute', inset: 0,
        background: 'linear-gradient(140deg, rgba(250,130,76,.78) 0%, rgba(45,128,242,.58) 100%)',
      }} />

      {/* Floating blobs */}
      <div className="shape s1" />
      <div className="shape s2" />
      <div className="shape s3" />
      <div className="shape s4" />
      <div className="shape s5" />
      <div className="shape s6" />

      {/* Content */}
      <div style={{ position: 'relative', textAlign: 'center', padding: '0 24px', maxWidth: 920 }}>
        <h1 style={{
          color: 'white',
          fontSize: 'clamp(3.2rem, 7vw, 5.8rem)',
          fontWeight: 900, lineHeight: 1.05, letterSpacing: '-1.5px',
          marginBottom: 22, transform: 'rotate(-1.5deg)',
          textShadow: '0 4px 24px rgba(0,0,0,.22)',
        }}>
          Your Home Away<br />From Home
        </h1>
        <p style={{
          color: 'rgba(255,255,255,.93)', fontSize: '1.25rem',
          fontWeight: 600, lineHeight: 1.65, marginBottom: 46,
        }}>
          Connecting internationals to community, friendship,<br />
          and belonging in Colorado
        </p>
        <div style={{ display: 'flex', gap: 16, justifyContent: 'center', flexWrap: 'wrap' }}>
          <button className="btn-orange" style={{
            background: '#fa824c', color: 'white', border: 'none',
            borderRadius: 32, padding: '16px 38px',
            fontFamily: 'Nunito, sans-serif', fontWeight: 800, fontSize: '1.05rem', cursor: 'pointer',
            boxShadow: '0 4px 18px rgba(250,130,76,.45)',
          }}>
            Join Our Community
          </button>
          <button className="btn-outline" style={{
            background: 'transparent', color: 'white',
            border: '2.5px solid white',
            borderRadius: 32, padding: '16px 38px',
            fontFamily: 'Nunito, sans-serif', fontWeight: 800, fontSize: '1.05rem', cursor: 'pointer',
          }}>
            Learn More
          </button>
        </div>
      </div>

      {/* Scroll indicator */}
      <div style={{
        position: 'absolute', bottom: 32, left: '50%', transform: 'translateX(-50%)',
        display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 7,
        color: 'rgba(255,255,255,.75)', fontSize: 12, fontWeight: 700,
      }}>
        <span style={{ letterSpacing: '.5px', textTransform: 'uppercase' }}>Scroll</span>
        <div style={{
          width: 24, height: 40,
          border: '2px solid rgba(255,255,255,.6)',
          borderRadius: 12, position: 'relative',
        }}>
          <div className="scroll-dot" />
        </div>
      </div>
    </section>
  );
}
